#!/usr/bin/env node

const fs = require("fs");
const path = require("path");
const esbuild = require("esbuild");
const LiveScript = require("livescript");
const { SourceMapConsumer, SourceMapGenerator } = require("livescript/node_modules/source-map");

const root = path.resolve(__dirname, "..");
const staticDir = path.join(root, "static");

const ethercalcInputs = [
  "node_modules/socialcalc/dist/SocialCalc.js",
  "static/socialcalc-compat.js",
  "third-party/class-js/lib/Class.js",
  "third-party/wikiwyg/lib/Document/Emitter.js",
  "third-party/wikiwyg/lib/Document/Emitter/HTML.js",
  "third-party/wikiwyg/lib/Document/Parser.js",
  "third-party/wikiwyg/lib/Document/Parser/Wikitext.js",
  "static/jquery.js",
  "static/vex.combined.min.js",
  "static/jquery-ui.min.js",
];

function cssInjectionPlugin() {
  return {
    name: "css-injection",
    setup(build) {
      build.onLoad({ filter: /\.css$/ }, async (args) => {
        const css = await fs.promises.readFile(args.path, "utf8");
        return {
          loader: "js",
          contents: `
            const style = document.createElement("style");
            style.textContent = ${JSON.stringify(css)};
            document.head.appendChild(style);
          `,
        };
      });
    },
  };
}

function livescriptPlugin() {
  return {
    name: "livescript",
    setup(build) {
      build.onLoad({ filter: /\.ls$/ }, async (args) => {
        try {
          const source = await fs.promises.readFile(args.path, "utf8");
          const contents = LiveScript.compile(source, {
            bare: true,
            filename: path.relative(root, args.path),
          });

          return {
            contents,
            loader: "js",
            resolveDir: path.dirname(args.path),
          };
        } catch (err) {
          return {
            errors: [{
              text: err.message,
              location: err.location && {
                file: args.path,
                line: err.location.first_line + 1,
                column: err.location.first_column,
              },
            }],
          };
        }
      });
    },
  };
}

function buildEthercalc() {
  const outFile = path.join(staticDir, "ethercalc.js");
  const sourceMapFile = `${outFile}.map`;
  let generated = generatedBanner("ethercalc.js");
  let line = countLines(generated);
  const generator = new SourceMapGenerator({ file: "ethercalc.js" });

  for (const file of ethercalcInputs) {
    const absolute = path.join(root, file);
    const sourcefile = path.relative(staticDir, absolute).replace(/\\/g, "/");
    const marker = `/* ${file} */\n`;
    const result = esbuild.transformSync(fs.readFileSync(absolute, "utf8"), {
      loader: "js",
      minify: true,
      sourcemap: "external",
      sourcefile,
      target: "es2017",
      legalComments: "none",
    });

    generated += marker;
    line += countLines(marker);
    appendSourceMap(generator, result.map, line);

    const code = `${result.code}\n;\n`;
    generated += code;
    line += countLines(code);
  }

  fs.mkdirSync(staticDir, { recursive: true });
  fs.writeFileSync(outFile, `${generated}//# sourceMappingURL=ethercalc.js.map\n`);
  fs.writeFileSync(sourceMapFile, generator.toString());
}

async function buildMulti() {
  const outFile = path.join(staticDir, "multi.js");

  fs.mkdirSync(staticDir, { recursive: true });

  await esbuild.build({
    entryPoints: [path.join(root, "multi", "main.ls")],
    bundle: true,
    banner: { js: generatedBanner("multi.js").trimEnd() },
    outfile: outFile,
    platform: "browser",
    format: "iife",
    minify: true,
    sourcemap: true,
    define: {
      "process.env.NODE_ENV": '"production"',
    },
    resolveExtensions: [".js", ".ls", ".css"],
    plugins: [livescriptPlugin(), cssInjectionPlugin()],
    logLevel: "warning",
  });
}

function copySocketIoClient() {
  fs.mkdirSync(staticDir, { recursive: true });
  fs.copyFileSync(
    path.join(root, "node_modules", "socket.io", "client-dist", "socket.io.min.js"),
    path.join(staticDir, "socket.io.js")
  );
}

function generatedBanner(file) {
  return `// Auto-generated by scripts/build-frontend.js for static/${file}; ALL CHANGES HERE WILL BE LOST!\n`;
}

function countLines(text) {
  return text.split("\n").length - 1;
}

function appendSourceMap(generator, mapText, lineOffset) {
  const consumer = new SourceMapConsumer(JSON.parse(mapText));

  consumer.eachMapping((mapping) => {
    if (mapping.originalLine == null) return;

    generator.addMapping({
      generated: {
        line: lineOffset + mapping.generatedLine,
        column: mapping.generatedColumn,
      },
      original: {
        line: mapping.originalLine,
        column: mapping.originalColumn,
      },
      source: mapping.source,
      name: mapping.name || undefined,
    });
  });

  for (const source of consumer.sources) {
    const content = consumer.sourceContentFor(source, true);
    if (content != null) generator.setSourceContent(source, content);
  }

  if (consumer.destroy) consumer.destroy();
}

async function main() {
  buildEthercalc();
  await buildMulti();
  copySocketIoClient();
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
